const alertMonths = parseInt($env.RUNWAY_ALERT_MONTHS || 12, 10);
const rows = $input.all().map(i=>i.json).sort((a,b)=>a.month<b.month?-1:1);
const last = rows[rows.length-1] || {};
const prev = rows[rows.length-2] || {};
const revenue = parseFloat(last.revenue||0);
const expenses = parseFloat(last.expenses||0);
const cash = parseFloat(last.cash_balance||0);
const burn = expenses - revenue;
const runway = burn > 0 ? Math.floor(cash/burn) : 9999;
const prev_burn = parseFloat(prev.expenses||0) - parseFloat(prev.revenue||0);
const burn_change = prev_burn > 0 ? ((burn-prev_burn)/prev_burn*100).toFixed(1) : null;
// Trailing 3-month average burn
const recent3 = rows.slice(-3);
const avg_burn_3m = recent3.length > 0 ? recent3.reduce((s,r)=>s+(parseFloat(r.expenses||0)-parseFloat(r.revenue||0)),0)/recent3.length : burn;
const runway_conservative = avg_burn_3m > 0 ? Math.floor(cash/avg_burn_3m) : 9999;
const default_rate = (revenue/expenses*100).toFixed(1);
const alert = runway <= alertMonths;
return [{ json: { month: last.month, revenue, expenses, net_burn: Math.round(burn), cash_balance: cash, runway_months: runway, runway_conservative_months: runway_conservative, burn_change_pct: burn_change, default_rate_pct: parseFloat(default_rate), headcount: last.headcount, alert, alert_threshold_months: alertMonths, generated_at: new Date().toISOString() } }];

